<x-filament-panels::page><main class="sfs"><header><div><span>SYSTEM / PRIVATE FILE SECURITY</span><h1>Security File Scanner</h1><p>Private evidence malware scanning and retention controls. No automatic deletion.</p></div><a href="{{$securityUrl}}">System Security</a></header><section class="kpis">@foreach([['Scanner',$readiness['selected_scanner']],['Availability',$readiness['is_available']?'Available':'Unavailable'],['Pending',$counts['pending_scan']??0],['Clean',$counts['clean']??0],['Unavailable',$counts['scan_unavailable']??0],['Retention candidates',$candidateCount]] as [$l,$v])<article><span>{{$l}}</span><strong>{{$v}}</strong></article>@endforeach</section><section class="grid"><section class="panel"><span>SCANNER SETTINGS</span><h2>{{$readiness['message']}}</h2><label>Selected scanner<select wire:model="scanner"><option value="disabled">Disabled</option><option value="clamav">ClamAV</option></select></label><label>ClamAV binary path<input wire:model="binaryPath" placeholder="/usr/bin/clamscan"></label><label>Timeout seconds<input type="number" wire:model="timeout"></label><label><input type="checkbox" wire:model="overrideEnabled"> Audited owner override enabled</label><button wire:click="saveSettings">Save settings</button><button wire:click="testScanner">Test scanner availability</button></section><section class="panel"><span>RETENTION CONTROL</span><h2>Dry-run first</h2><label><input type="checkbox" wire:model="retentionEnabled"> Retention enabled</label><label><input type="checkbox" checked disabled> Dry-run only enforced</label><label>Default retention days<input type="number" wire:model="retentionDays"></label><button wire:click="createDryRun">Run retention dry-run</button><button disabled title="Physical deletion is dry-run only.">Execute deletion unavailable</button></section></section><section class="panel"><span>EVIDENCE SCAN STATUS</span><h2>Recent private evidence</h2>@forelse($evidence as $item)<div class="row"><strong>#{{$item->id}} {{$item->original_filename}}</strong><em>{{$item->scan_status}} · {{$item->scan_engine?:'no scanner'}} · {{$item->scanned_at?->format('Y-m-d H:i')?:'not scanned'}}</em></div>@empty<p>No evidence records.</p>@endforelse</section><section class="panel"><span>RETENTION JOBS</span><h2>Audited dry runs</h2>@forelse($jobs as $job)<div class="row"><strong>{{$job->job_number}} · {{$job->status}}</strong><em>{{$job->candidate_count}} candidate(s), {{$job->deleted_count}} deleted</em></div>@empty<p>No retention jobs.</p>@endforelse</section></main><style>.sfs{color:#eaf4ff;display:grid;gap:14px}.sfs header,.panel,.kpis article{background:#071725;border:1px solid #20384b;border-radius:8px}.sfs header{display:flex;justify-content:space-between;padding:20px}.sfs span{color:#55e6b2;font-size:11px;font-weight:800}.sfs h1{font-size:30px;margin:5px 0}.sfs p,.sfs em{color:#94abc1}.sfs a,.sfs button{background:#0b2937;border:1px solid #286078;border-radius:6px;color:#eaffff;padding:9px 12px;font-weight:700}.kpis{display:grid;grid-template-columns:repeat(6,1fr);gap:10px}.kpis article,.panel{padding:14px}.kpis strong{display:block;font-size:18px;margin-top:7px}.grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}.row{display:flex;justify-content:space-between;gap:12px;padding:11px 0;border-bottom:1px solid #20384b}.sfs label{display:grid;gap:5px;margin-top:12px;color:#9db2c7}.sfs input,.sfs select{background:#06131f;border:1px solid #29465b;color:#fff;padding:10px;border-radius:5px}.sfs button{margin-top:10px}@media(max-width:800px){.kpis,.grid{grid-template-columns:1fr 1fr}.sfs header,.row{display:block}}</style></x-filament-panels::page>
